void QMC5883P::calibration(void)
{
    char buffer[64] = {0};
    
    float m[3] = {0};
    float max[3] = {-999, -999, -999};
    float min[3] = {999, 999, 999};
    
    int test_count = 0;
    while(1) 
    {
        update();
        m[0] = getX();
        m[1] = getY();
        m[2] = getZ();
        
        
        // 載陔郔湮郔苤硉
        for(int i = 0; i < 3; i++) {
            if(m[i] > max[i]) max[i] = m[i];
            if(m[i] < min[i]) min[i] = m[i];
        }
        
        // 數呾苺袧統杅
        float offset[3], scale[3];
        for(int i = 0; i < 3; i++) {
            offset[i] = (max[i] + min[i]) / 2.0f;
            scale[i] = (max[i] - min[i]) / 2.0f;  // 圉粣酗僅
        }
        
        // 眕郔湮粣峈價袧寥珨趙
        float max_scale = fmaxf(scale[0], fmaxf(scale[1], scale[2]));
        for(int i = 0; i < 3; i++) {
            scale[i] = max_scale / scale[i];
        }
        
        sprintf(buffer, "%.6f,%.6f,%.6f,%.6f,%.6f,%.6f\n", offset[0], offset[1], offset[2], scale[0], scale[1], scale[2]);

        Delay(20);
        
        if(++test_count % 100 == 0) 
        {
            _offset_x = offset[0]; _offset_y = offset[1]; _offset_z = offset[2];
            _scale_x = scale[0]; _scale_y = scale[1]; _scale_z = scale[2];

            update();

            float horiz_norm = sqrtf(getX()*getX() + getY()*getY());
            
            // 軞耀酗茼蜆箝隅
            float total_norm = sqrtf(getX()*getX() + getY()*getY() + getZ()*getZ());
                
            printf("horiz=%.3f, total=%.3f, mz=%.3f------------------------------\n",
                horiz_norm, total_norm, getZ());

            _offset_x = 0; _offset_y = 0; _offset_z = 0;
            _scale_x = 1; _scale_y = 1; _scale_z = 1;
        }

        Delay(20);
    }
}

